from pathlib import Path
from collections import Counter,defaultdict
root=Path('awesome-codex-skills')
for lang in ['en','zh']:
    names=[]
    paths=[]
    for p in sorted((root/lang).rglob('SKILL.md')):
        names.append(p.parent.name)
        paths.append(p)
    c=Counter(names)
    dup={k:v for k,v in c.items() if v>1}
    print(lang, 'skill files', len(paths), 'unique parent names', len(c), 'dups', dup)
    if dup:
        d=defaultdict(list)
        for p in paths:
            if c[p.parent.name]>1:
                d[p.parent.name].append(str(p.relative_to(root/lang)))
        for k,v in d.items(): print(k, v)
