from pathlib import Path
root = Path('awesome-codex-skills')
counts = {}
files = []
for p in root.rglob('SKILL.md'):
    in_fence = False
    hits = []
    for i, line in enumerate(p.read_text(encoding='utf-8').splitlines(), 1):
        stripped = line.strip()
        if stripped.startswith('```') or stripped.startswith('~~~'):
            in_fence = not in_fence
            continue
        if in_fence:
            continue
        if stripped.startswith('<') and stripped.endswith('>') and len(stripped) > 2:
            # Skip common HTML comments/doctype and simple markdown autolinks are not standalone in our files.
            if stripped.startswith(('<!--', '<!DOCTYPE', '<?')):
                continue
            # Only report plain tag-like single lines.
            inner = stripped[1:-1].strip('/').strip()
            if inner and all(ch.isalnum() or ch in '-_ ' for ch in inner):
                hits.append((i, stripped))
                counts[stripped] = counts.get(stripped, 0) + 1
    if hits:
        files.append((p, hits))
print('files_with_raw_tags', len(files))
print('total_raw_tag_lines', sum(len(h) for _, h in files))
for tag, n in sorted(counts.items(), key=lambda kv: (-kv[1], kv[0])):
    print(f'{n:4} {tag}')
print('\nfirst_40_files')
for p, hits in files[:40]:
    preview = ', '.join(f'{ln}:{tag}' for ln, tag in hits[:6])
    print(f'{p}: {preview}')
